#include "interface.h"

#include <roaring.h>

uint64_t many_union_cardinality(
    const std::vector<uint32_t>& offsets,
    const std::vector<uint32_t>& values) {
  const std::size_t num_shards = offsets.size() - 1;
  if (num_shards == 0) {
    return 0;
  }

  if (num_shards == 1) {
    roaring_bitmap_t* bitmap = roaring_bitmap_create();
    const uint32_t begin = offsets[0];
    const uint32_t end = offsets[1];
    if (end > begin) {
      roaring_bitmap_add_many(bitmap, end - begin, &values[begin]);
    }
    uint64_t result = roaring_bitmap_get_cardinality(bitmap);
    roaring_bitmap_free(bitmap);
    return result;
  }

  roaring_bitmap_t* bitmaps[num_shards];
  for (std::size_t shard = 0; shard < num_shards; ++shard) {
    const uint32_t begin = offsets[shard];
    const uint32_t end = offsets[shard + 1];
    bitmaps[shard] = roaring_bitmap_create();
    if (end > begin) {
      roaring_bitmap_add_many(bitmaps[shard], end - begin, &values[begin]);
    }
  }

  roaring_bitmap_t* accumulated = roaring_bitmap_copy(bitmaps[0]);
  for (std::size_t shard = 1; shard < num_shards; ++shard) {
    roaring_bitmap_or_inplace(accumulated, bitmaps[shard]);
  }

  uint64_t result = roaring_bitmap_get_cardinality(accumulated);

  roaring_bitmap_free(accumulated);
  for (std::size_t shard = 0; shard < num_shards; ++shard) {
    roaring_bitmap_free(bitmaps[shard]);
  }

  return result;
}
